mapper.select:
select a.*,
       c.course_name,
       u.real_name as member_name
from checkin_record a
         left join repertoire_info c on a.course_id = c.id
         left join sys_user u on a.member_id = u.id


        and a.schedule_id = #{scheduleId}


        and a.member_id = #{memberId}


        and a.artist_id = #{artistId}


order by a.id desc

mapper.update:
update checkin_record
attendance_date = #{attendanceDate}, attendance_status = #{attendanceStatus}, remark = #{remark},
where id = #{id}
